key_snippets.sub_container_data_fetching:
const {
  data,
  query: { isFetching, error },
} = useOrders({
  advertiserId: params.advertiserId,
  inquiryEntityStatusOption: MEInquiryEntityStatusOption.INQUIRY_ENTITY_STATUS_UNARCHIVED,
  inquiryRelatedEntityOption: MEInquiryRelatedEntityOption.INQUIRY_ENTITY_ALL,
});

useEffect(() => {
  if (error) {
    fireCollapsibleError({ summary: t('errors.list'), error });
  }
}, [error, fireCollapsibleError, t]);

return (
  <MCOrderListTableContainer orders={availableOrders} type="available" isFetching={isFetching} />
);

