container_error_handling.template:
const { fireCollapsibleError } = useInAppAlert();

useEffect(() => {
  if (error) {
    fireCollapsibleError({ summary: t('errors.{action}'), error });
  }
}, [error, fireCollapsibleError, t]);

container_tab_state.template:
const [searchParams, setSearchParams] = useSearchParams();
const activeTab = searchParams.get('{PARAM_KEY}');

useEffect(() => {
  if (!isValidTab(activeTab)) {
    setSearchParams({ [PARAM_KEY]: 'available' }, { replace: true });
  }
}, [activeTab, setSearchParams]);

container_create_button.template:
const handleCreate = useCallback(() => {
  const path = generatePathForRoute(MERouteKey.{ENTITY}_CREATE, params);
  navigate(path);
}, [navigate, params]);

const rightAccessory = useMemo(() => (
  <MCButton2 color="primary" onClick={handleCreate} leftIcon="create">
    {t('create')}
  </MCButton2>
), [handleCreate, t]);
